// Pick a random ASMR topic
const topics = [
  'gentle rain on a rooftop at night',
  'forest meditation with birdsong and rustling leaves',
  'ocean waves crashing softly on a sandy beach',
  'crackling fireplace with distant wind',
  'library ambience with soft page turning',
  'Japanese zen garden with bamboo water feature',
  'coffee shop background with soft chatter',
  'thunderstorm from inside a cozy cabin'
];

const today = new Date();
const index = today.getDate() % topics.length;
const topic = topics[index];

return [{ json: { topic, date: today.toISOString().split('T')[0] } }];

