// Parse Claude response and extract script content
const response = $input.item.json;
const content = response.content?.[0]?.text || '{}';

let parsed;
try {
  // Extract JSON from Claude's response (may be wrapped in markdown)
  const jsonMatch = content.match(/```json\n([\s\S]*?)\n```/) || content.match(/({[\s\S]*})/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[1] || jsonMatch[0]) : JSON.parse(content);
} catch(e) {
  parsed = {
    title: 'Relaxing ASMR - ' + new Date().toLocaleDateString(),
    script: content,
    description: 'Relaxing ASMR video for sleep and meditation.',
    tags: ['asmr', 'relaxing', 'sleep', 'meditation', 'ambient']
  };
}

return [{ json: { ...parsed, topic: $('Pick ASMR Topic').item.json.topic, date: $('Pick ASMR Topic').item.json.date } }];

// Prepare metadata for video creation
// Audio binary is available as binary data from previous node
const scriptData = $('Parse Script Response').item.json;

// Build FFmpeg command for reference (user runs this or integrates with server)
const ffmpegCmd = `ffmpeg -loop 1 -i background.jpg -i audio.mp3 -c:v libx264 -tune stillimage -c:a aac -b:a 192k -pix_fmt yuv420p -shortest output.mp4`;

const metadata = {
  title: scriptData.title,
  description: scriptData.description,
  tags: Array.isArray(scriptData.tags) ? scriptData.tags : ['asmr', 'relaxing', 'meditation'],
  categoryId: '22',  // People & Blogs — change to 26 (Howto) if preferred
  privacyStatus: 'public',
  ffmpegCommand: ffmpegCmd,
  audioReady: true,
  note: 'Audio binary is in binary data. Use FFmpeg node or server script to combine with background image.'
};

return [{ json: metadata }];

